import os
from pathlib import Path
from typing import Annotated

from fastapi import FastAPI, Request, Form, HTTPException, status
from fastapi.responses import HTMLResponse, RedirectResponse
from fastapi.staticfiles import StaticFiles
from fastapi.templating import Jinja2Templates

# --- FastAPI Application Setup ---
app = FastAPI(
    title="Neuro-Link Cyberpunk Login",
    description="A FastAPI backend for a cyberpunk-themed login page."
)

# --- Directory Setup ---
# Get the absolute path to the current directory (where main.py is located)
BASE_DIR = Path(__file__).resolve().parent

# --- Static Files Configuration ---
# Mount the 'static' directory to serve CSS, JS, images, etc.
# These files will be accessible under the /static/ URL path.
app.mount("/static", StaticFiles(directory=BASE_DIR / "static"), name="static")

# --- Jinja2 Templates Configuration ---
# Configure Jinja2Templates to load templates from the 'templates' directory.
# Templates will be rendered by the server.
templates = Jinja2Templates(directory=BASE_DIR / "templates")

# --- Dummy User Credentials (for demonstration purposes only) ---
# In a real application, these would be securely stored and retrieved
# from a database, and passwords would be hashed (e.g., using bcrypt).
VALID_USERNAME = os.getenv("NEURAL_ID", "admin_id")
VALID_PASSWORD = os.getenv("PASSPHRASE", "secure_pass")

# --- Routes ---

@app.get("/", response_class=HTMLResponse, summary="Serve Login Page")
async def get_login_page(request: Request):
    """Displays the cyberpunk-themed login page."""
    return templates.TemplateResponse(
        "index.html",
        {"request": request, "error_message": None}
    )

@app.post("/login", response_class=HTMLResponse, summary="Handle Authentication")
async def login(
    request: Request,
    neural_id: Annotated[str, Form(min_length=3, max_length=50)] = None,
    passphrase: Annotated[str, Form(min_length=6, max_length=100)] = None
):
    """Handles the submission of login credentials and authenticates the user.

    - If authentication is successful, redirects to a success page (or a placeholder).
    - If authentication fails, re-renders the login page with an error message.
    """
    if not neural_id or not passphrase:
        return templates.TemplateResponse(
            "index.html",
            {"request": request, "error_message": "Neural ID and Passphrase are required."}
        )

    # --- Dummy Authentication Logic ---
    # This is a simplified check for demonstration. Replace with real authentication.
    if neural_id == VALID_USERNAME and passphrase == VALID_PASSWORD:
        # In a real app, a session token or JWT would be issued here.
        # For this demo, a simple redirect to a success message.
        return RedirectResponse(url="/dashboard", status_code=status.HTTP_302_FOUND)
    else:
        return templates.TemplateResponse(
            "index.html",
            {"request": request, "error_message": "Invalid Neural ID or Passphrase. Access Denied."}
        )

@app.get("/dashboard", response_class=HTMLResponse, summary="User Dashboard/Success Page")
async def dashboard(request: Request):
    """A placeholder page for successful login."""
    content = """
    <!DOCTYPE html>
    <html lang="en">
    <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <title>Access Granted</title>
        <link rel="stylesheet" href="/static/style.css">
        <style>
            body {
                display: flex;
                justify-content: center;
                align-items: center;
                min-height: 100vh;
                background-color: #000;
                color: #0ff;
                font-family: 'Share Tech Mono', monospace;
            }
            .message-container {
                text-align: center;
                padding: 40px;
                border: 2px solid #0ff;
                box-shadow: 0 0 15px #0ff, inset 0 0 10px #0ff;
                animation: neon-pulse 1.5s infinite alternate;
            }
            h1 {
                font-size: 3em;
                margin-bottom: 20px;
                text-shadow: 0 0 10px #0ff;
            }
            p {
                font-size: 1.2em;
            }
            @keyframes neon-pulse {
                from { box-shadow: 0 0 15px #0ff, inset 0 0 10px #0ff; }
                to { box-shadow: 0 0 25px #0ff, inset 0 0 15px #0ff; }
            }
        </style>
    </head>
    <body>
        <div class="message-container">
            <h1>ACCESS GRANTED</h1>
            <p>Welcome, Data Ghost. Your neural link is active.</p>
            <p>Proceed with caution.</p>
            <p><a href="/" style="color: #0ff; text-decoration: none; border-bottom: 1px dotted #0ff;">Return to Matrix Gate</a></p>
        </div>
    </body>
    </html>
    """
    return HTMLResponse(content=content)

